#include <bits/stdc++.h>
using namespace std;

void to_ints(string s, int it[205], int &len) {
    int l = s.size();
    while (s[0] == '0' && l > 0) {
        s.erase(s.begin());
        l--;
    }
    if (l == 0) {
        it[0] = 0;
        len = 1;
        return ;
    }
    len = 0;
    for (int i = 0; i < l; i++) {
        it[l - i - 1] = s[i] - '0';
        len++;
    }
    it[len] = 0;
}

void print(int x[205], int len) {
    for (int i = len - 1; i >= 0; i--) {
        cout << x[i];
    }
    cout << endl;
}

void add(int a[205], int b[205], int la, int lb, int &l) {
    l = max(la, lb);
    for (int i = 0; i < l; i++) {
        int t = a[i] + b[i];
        a[i] = t % 10;
        if (t > 9) {
            a[i + 1] += t / 10;
            if (i == l - 1) {
                l++;
            }
        }
    }
}

int main() {
    int a[205], b[205], la, lb, l;
    string s1, s2;

    cin >> s1 >> s2;
    to_ints(s1, a, la);
    to_ints(s2, b, lb);

    add(a, b, la, lb, l);
    print(a, l);
    return 0;
}
